import React, { useState } from "react";
import DenteSVG from "./DenteSVG";
import ModalTratamentoFace from "./ModalTratamentoFace";

// ...dentes, etc...

export default function OdontogramaAvancado() {
  // ... outros states
  const [modal, setModal] = useState({ open: false, dente: null, face: null });

  function handleFaceClick(num, face) {
    setModal({ open: true, dente: num, face });
  }

  function handleSaveTratamento(trat) {
    // Salve o tratamento (trat.dente, trat.face, trat.tratamento)
    // Aqui pode chamar API ou atualizar estado!
    setModal({ open: false, dente: null, face: null });
    alert(`Salvo: ${trat.tratamento} em ${trat.face} do dente ${trat.dente}`);
  }

  return (
    <div>
      {/* Renderize os dentes com DenteSVG */}
      <div className="flex flex-wrap gap-2">
        {[11, 12, 13, 14, 15].map(num => (
          <DenteSVG key={num} numero={num} onFaceClick={handleFaceClick} />
        ))}
        {/* ...adicione todos os dentes... */}
      </div>
      {/* Modal */}
      <ModalTratamentoFace
        open={modal.open}
        face={modal.face}
        dente={modal.dente}
        onClose={() => setModal({ open: false, dente: null, face: null })}
        onSave={handleSaveTratamento}
      />
    </div>
  );
}
